mapper.insert:
insert into seat_reservation

    seat_id
    user_id
    date
    start_time
    end_time
    reservation_no

    values

        #{seatId}
        #{userId}
        #{date}
        #{startTime}
        #{endTime}
        #{reservationNo}

mapper.select:
select r.id, stu.name as userName, r.seat_id, s.seat_number,
       r.date, r.start_time, r.end_time, r.leave_time, r.status, r.reservation_no as reservationNo,
       r.create_time, r.update_time, s.room_id
from seat_reservation r
left join student stu on r.user_id = stu.id
left join seat s on r.seat_id = s.id

    and r.user_id = #{userId}
    and r.seat_id = #{seatId}
    and r.date = #{date}
    and r.status = #{status}

order by r.create_time desc
